import{_ as t,o,c as s,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Import et export de donnees","description":"","frontmatter":{},"headers":[],"relativePath":"fr/account/data.md","filePath":"fr/account/data.md"}'),n={name:"fr/account/data.md"};function a(i,e,l,d,p,c){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="import-et-export-de-donnees" tabindex="-1">Import et export de donnees <a class="header-anchor" href="#import-et-export-de-donnees" aria-label="Permalink to &quot;Import et export de donnees&quot;">​</a></h1><p>Importez des donnees existantes dans MyCompanyDesk et exportez vos enregistrements pour sauvegarde ou utilisation dans d&#39;autres outils.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><h3 id="import-csv" tabindex="-1">Import CSV <a class="header-anchor" href="#import-csv" aria-label="Permalink to &quot;Import CSV&quot;">​</a></h3><p>Importez des donnees depuis des fichiers CSV pour :</p><ul><li><strong>Clients</strong> -- Nom, e-mail, telephone, adresse, numero de TVA</li><li><strong>Factures</strong> -- Details des factures avec lignes de facturation</li><li><strong>Depenses</strong> -- Enregistrements de depenses avec categories</li><li><strong>Projets</strong> -- Noms et details des projets</li><li><strong>Objets</strong> -- Enregistrements d&#39;actifs</li></ul><h3 id="comment-importer" tabindex="-1">Comment importer <a class="header-anchor" href="#comment-importer" aria-label="Permalink to &quot;Comment importer&quot;">​</a></h3><ol><li>Allez dans <strong>Profil &gt; Import</strong></li><li>Selectionnez le <strong>type de donnees</strong> que vous souhaitez importer</li><li>Telechargez votre <strong>fichier CSV</strong></li><li><strong>Faites correspondre les colonnes</strong> -- Associez les en-tetes de colonnes de votre CSV aux champs MyCompanyDesk</li><li><strong>Apercu</strong> -- Verifiez les donnees avant l&#39;import</li><li><strong>Confirmez</strong> -- Cliquez sur Importer pour creer les enregistrements</li></ol><h3 id="conseils-d-import" tabindex="-1">Conseils d&#39;import <a class="header-anchor" href="#conseils-d-import" aria-label="Permalink to &quot;Conseils d&#39;import&quot;">​</a></h3><ul><li>Utilisez l&#39;encodage UTF-8 pour vos fichiers CSV</li><li>Incluez une ligne d&#39;en-tete avec les noms de colonnes</li><li>Les formats de date doivent etre coherents (AAAA-MM-JJ recommande)</li><li>Les champs de montant doivent utiliser le point (.) comme separateur decimal</li><li>Les champs vides sont ignores (les valeurs par defaut existantes sont utilisees)</li></ul><h3 id="correspondance-des-colonnes" tabindex="-1">Correspondance des colonnes <a class="header-anchor" href="#correspondance-des-colonnes" aria-label="Permalink to &quot;Correspondance des colonnes&quot;">​</a></h3><p>L&#39;assistant d&#39;import affiche vos colonnes CSV et vous permet de faire correspondre chacune au champ MyCompanyDesk correspondant. Correspondances courantes :</p><table tabindex="0"><thead><tr><th>Colonne CSV</th><th>Correspond a</th></tr></thead><tbody><tr><td>Company Name / Name</td><td>Nom du client</td></tr><tr><td>Email</td><td>E-mail du client</td></tr><tr><td>Street / Address</td><td>Adresse</td></tr><tr><td>ZIP / Postal Code</td><td>Code postal</td></tr><tr><td>City</td><td>Ville</td></tr><tr><td>VAT / BTW</td><td>Numero de TVA</td></tr><tr><td>Phone</td><td>Numero de telephone</td></tr></tbody></table><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><h3 id="export-csv" tabindex="-1">Export CSV <a class="header-anchor" href="#export-csv" aria-label="Permalink to &quot;Export CSV&quot;">​</a></h3><p>Exportez vos donnees au format CSV depuis les pages de listes respectives :</p><ul><li><strong>Factures</strong> -- Toutes les factures avec montants, dates, statuts</li><li><strong>Depenses</strong> -- Toutes les depenses avec categories et montants</li><li><strong>Clients</strong> -- Votre base de donnees clients</li></ul><p>Cliquez sur le bouton <strong>Exporter</strong> sur la page de liste pour telecharger.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>L&#39;export CSV necessite le plan <strong>Pro</strong> ou superieur.</p></div><h3 id="export-de-donnees-rgpd" tabindex="-1">Export de donnees RGPD <a class="header-anchor" href="#export-de-donnees-rgpd" aria-label="Permalink to &quot;Export de donnees RGPD&quot;">​</a></h3><p>Exportez toutes vos donnees personnelles au format JSON :</p><ol><li>Allez dans <strong>Profil &gt; Donnees</strong></li><li>Cliquez sur <strong>Exporter mes donnees</strong></li><li>Telechargez le fichier JSON contenant toutes les donnees de votre compte</li></ol><p>Cet export RGPD comprend :</p><ul><li>Vos informations de profil</li><li>Toutes les factures, depenses, devis</li><li>Les fiches clients</li><li>Les donnees de projets et de temps</li><li>Les parametres et preferences</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Exportez vos donnees regulierement en guise de sauvegarde</li><li>Utilisez l&#39;export CSV pour partager des donnees avec votre comptable</li><li>Lorsque vous migrez depuis un autre outil, utilisez l&#39;assistant d&#39;import pour migrer votre liste de clients</li><li>L&#39;export RGPD fournit un instantane complet de vos donnees</li></ul>',26)])])}const h=t(n,[["render",a]]);export{m as __pageData,h as default};
